function Login() {
  return (
    <div
      style={{
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        alignItems: "center",
        fontFamily: "Arial",
        background: "#f8fafc",
      }}
    >
      <h2>Login</h2>

      <input placeholder="Username" style={{ margin: "8px", padding: "10px" }} />
      <input
        type="password"
        placeholder="Password"
        style={{ margin: "8px", padding: "10px" }}
      />

      <button
        style={{
          marginTop: "15px",
          padding: "10px 24px",
          backgroundColor: "#2563eb",
          color: "white",
          border: "none",
          borderRadius: "6px",
        }}
      >
        Login
      </button>
    </div>
  );
}

export default Login;
